const aiOutput = $input.item.json;

// --- 1. EXTRACT AND PARSE THE OUTPUT ---
const aiResponseText = aiOutput.output || aiOutput.text || aiOutput;
let parsedOutput;
let userMessage;
let finished = false;
let agentData = null;

try {
  // Remove markdown code fences if present
  let cleanedText = aiResponseText.trim();

  if (cleanedText.startsWith('```json')) {
    cleanedText = cleanedText.replace(/^```json\s*\n?/, '').replace(/\n?```\s*$/, '');
  } else if (cleanedText.startsWith('```')) {
    cleanedText = cleanedText.replace(/^```\s*\n?/, '').replace(/\n?```\s*$/, '');
  }

  const firstParse = JSON.parse(cleanedText);
  parsedOutput = firstParse;

  userMessage = firstParse.message || aiResponseText;
  finished = firstParse.finished || false;
  agentData = firstParse.agent_data || null;

} catch (e) {
  userMessage = aiResponseText;
  console.error('Parse error:', e.message);
}

// --- 2. CALCULATE TOKENS ---
let totalInput = 0;
let totalOutput = 0;
let totalCombined = 0;

function addUsage(u) {
  if (!u) return;
  totalInput += (u.prompt_tokens || u.input_tokens || 0);
  totalOutput += (u.completion_tokens || u.output_tokens || 0);
  totalCombined += (u.total_tokens || 0);
}

// Top-level usage
addUsage(aiOutput.tokenUsage);

// Intermediate steps
if (aiOutput.intermediateSteps && Array.isArray(aiOutput.intermediateSteps)) {
  aiOutput.intermediateSteps.forEach(step => {
    const logs = step.action?.messageLog || [];
    logs.forEach(log => {
      addUsage(log.kwargs?.usage_metadata); 
      addUsage(log.kwargs?.response_metadata?.usage); 
      addUsage(log.kwargs?.additional_kwargs?.usage);
    });
  });
}

// --- 3. BUILD THE RETURN OBJECT ---
return {
  json: {
    // Context (UPDATED)
    user_id: $('Webhook').first().json.body.user_id,
    user_mssg: $('Webhook').first().json.body.user_mssg,
    session_id: $('Webhook').first().json.body.session_id,
    timestamp_of_call_made: $('Webhook').first().json.body.timestamp_of_call_made,
    request_id: $('Webhook').first().json.body.request_id,

    // The Message (cleaned)
    agent_response: userMessage.trim(),

    // Parsed values
    finished: finished,
    agent_data: agentData,

    // Token Usage
    usage_metadata: {
      input_tokens: totalInput,
      output_tokens: totalOutput,
      total_tokens: totalCombined
    },

    // Raw Steps (for Tool Logger)
    intermediateSteps: aiOutput.intermediateSteps || []
  }
};

// 1. Get the data passed down from Code1
const inputData = $input.first().json;
const steps = inputData.intermediateSteps || [];

const returnItems = [];

// 2. Loop through all steps to find tools
steps.forEach((step) => {
  // Check if this step has a tool action
  if (step.action && step.action.tool) {
    returnItems.push({
      json: {
        // --- The Tool Data ---
        tool_name: step.action.tool,
        tool_args: step.action.toolInput,
        tool_output: step.observation,

        // --- Keep the Context for Supabase ---
        user_id: inputData.user_id,
        session_id: inputData.session_id,
        request_id: inputData.request_id
      }
    });
  }
});

// 3. Return separate items 
// (n8n will automatically run the next node once for each tool found)
// (If array is empty, the flow stops here automatically)
return returnItems;

